139→func tlsVersionString(v uint16) string {
140→	switch v {
141→	case tls.VersionTLS10:
142→		return "1.0"
143→	case tls.VersionTLS11:
144→		return "1.1"
145→	case tls.VersionTLS12:
146→		return "1.2"
147→	case tls.VersionTLS13:
148→		return "1.3"
149→	default:
150→		return fmt.Sprintf("unknown (0x%04x)", v)
151→	}
152→}
