 58→func runServeDB(ctx context.Context, dbPath, dn string, port int, mtls, verbose bool) error {
 59→	d, err := store.OpenDB(ctx, dbPath)
 60→	if err != nil {
 61→		return err
 62→	}
 63→	defer d.Close()
 64→
 65→	q := store.New(d.SqlDB())
 66→
 67→	certRow, err := q.GetCertByCN(ctx, dn)
 68→	if err != nil {
 69→		return fmt.Errorf("certificate %q not found", dn)
 70→	}
 71→
 72→	keyPEM, err := q.LoadKey(ctx, certRow.Serial)
 73→	if err != nil {
 74→		return fmt.Errorf("loading private key: %w", err)
 75→	}
 76→
 77→	tlsCert, err := tls.X509KeyPair([]byte(certRow.CertPem), keyPEM)
 78→	if err != nil {
 79→		return fmt.Errorf("loading TLS keypair: %w", err)
 80→	}
 81→
 82→	// Load all CAs for mTLS verification
 83→	var clientCAs *x509.CertPool
 84→	if mtls {
 85→		clientCAs = x509.NewCertPool()
 86→		cas, err := q.ListCAs(ctx)
 87→		if err == nil {
 88→			for _, c := range cas {
 89→				clientCAs.AppendCertsFromPEM([]byte(c.CertPem))
 90→			}
 91→		}
 92→	}
 93→
 94→	return startServer(tlsCert, clientCAs, port, mtls, verbose)
 95→}
