 97→func runServeFile(_ context.Context, certFile, pkeyFile string, port int, mtls, verbose bool) error {
 98→	tlsCert, err := tls.LoadX509KeyPair(certFile, pkeyFile)
 99→	if err != nil {
100→		return fmt.Errorf("loading TLS keypair: %w", err)
101→	}
102→
103→	var clientCAs *x509.CertPool
104→	if mtls {
105→		clientCAs, err = x509.SystemCertPool()
106→		if err != nil {
107→			clientCAs = x509.NewCertPool()
108→		}
109→	}
110→
111→	return startServer(tlsCert, clientCAs, port, mtls, verbose)
112→}
113→
114→func startServer(cert tls.Certificate, clientCAs *x509.CertPool, port int, mtls, verbose bool) error {
115→	clientAuth := tls.NoClientCert
116→	if mtls {
117→		clientAuth = tls.RequireAndVerifyClientCert
118→	}
119→
120→	tlsConf := &tls.Config{
121→		Certificates: []tls.Certificate{cert},
122→		ClientAuth:   clientAuth,
123→		ClientCAs:    clientCAs,
124→	}
125→
126→	mux := http.NewServeMux()
127→	mux.HandleFunc("/", echoHandler(verbose))
128→
129→	server := &http.Server{
130→		Addr:      fmt.Sprintf(":%d", port),
131→		Handler:   mux,
132→		TLSConfig: tlsConf,
133→	}
134→
135→	fmt.Printf("Listening on https://0.0.0.0:%d", port)
136→	if mtls {
137→		fmt.Print(" (mTLS enabled)")
138→	}
139→	fmt.Println()
140→
141→	return server.ListenAndServeTLS("", "")
142→}
