144→type echoResponse struct {
145→	URI     string            `json:"uri"`
146→	Method  string            `json:"method"`
147→	Headers map[string]string `json:"headers,omitempty"`
148→	Form    map[string]string `json:"form,omitempty"`
149→	Body    string            `json:"body,omitempty"`
150→	Peer    *peerInfo         `json:"peer,omitempty"`
151→}
