160→func echoHandler(verbose bool) http.HandlerFunc {
161→	return func(w http.ResponseWriter, r *http.Request) {
162→		resp := echoResponse{
163→			URI:    r.RequestURI,
164→			Method: r.Method,
165→		}
166→
167→		if verbose {
168→			resp.Headers = make(map[string]string)
169→			for k, v := range r.Header {
170→				resp.Headers[k] = v[0]
171→			}
172→		}
173→
174→		if r.Method == http.MethodPost || r.Method == http.MethodPut {
175→			_ = r.ParseForm()
176→			if len(r.Form) > 0 {
177→				resp.Form = make(map[string]string)
178→				for k, v := range r.Form {
179→					resp.Form[k] = v[0]
180→				}
181→			}
182→		}
183→
184→		if r.TLS != nil && len(r.TLS.PeerCertificates) > 0 {
185→			peer := r.TLS.PeerCertificates[0]
186→			resp.Peer = &peerInfo{
187→				Subject: peer.Subject.String(),
188→				Issuer:  peer.Issuer.String(),
189→				Serial:  fmt.Sprintf("%X", peer.SerialNumber),
190→				Expiry:  peer.NotAfter.Format(time.RFC3339),
191→			}
192→		}
193→
194→		w.Header().Set("Content-Type", "application/json")
195→		json.NewEncoder(w).Encode(resp)
196→	}
197→}
