 14→func generateKey(algo string, size int, curve string) (any, []byte, error) {
 15→	switch algo {
 16→	case "rsa":
 17→		key, err := rsa.GenerateKey(rand.Reader, size)
 18→		if err != nil {
 19→			return nil, nil, fmt.Errorf("generating RSA key: %w", err)
 20→		}
 21→		keyPEM := pem.EncodeToMemory(&pem.Block{
 22→			Type:  "RSA PRIVATE KEY",
 23→			Bytes: x509.MarshalPKCS1PrivateKey(key),
 24→		})
 25→		return key, keyPEM, nil
 26→	case "ecdsa":
 27→		c, err := parseCurve(curve)
 28→		if err != nil {
 29→			return nil, nil, err
 30→		}
 31→		key, err := ecdsa.GenerateKey(c, rand.Reader)
 32→		if err != nil {
 33→			return nil, nil, fmt.Errorf("generating ECDSA key: %w", err)
 34→		}
 35→		der, err := x509.MarshalECPrivateKey(key)
 36→		if err != nil {
 37→			return nil, nil, fmt.Errorf("marshalling ECDSA key: %w", err)
 38→		}
 39→		keyPEM := pem.EncodeToMemory(&pem.Block{Type: "EC PRIVATE KEY", Bytes: der})
 40→		return key, keyPEM, nil
 41→	default:
 42→		return nil, nil, fmt.Errorf("unsupported key algorithm: %s", algo)
 43→	}
 44→}
 45→
 46→func parseCurve(name string) (elliptic.Curve, error) {
 47→	switch name {
 48→	case "P-256":
 49→		return elliptic.P256(), nil
 50→	case "P-384":
 51→		return elliptic.P384(), nil
 52→	case "P-521":
 53→		return elliptic.P521(), nil
 54→	default:
 55→		return nil, fmt.Errorf("unsupported curve: %s", name)
 56→	}
 57→}
