 78→func parsePrivateKey(keyPEM []byte) (any, error) {
 79→	block, _ := pem.Decode(keyPEM)
 80→	if block == nil {
 81→		return nil, fmt.Errorf("failed to decode PEM")
 82→	}
 83→	switch block.Type {
 84→	case "RSA PRIVATE KEY":
 85→		return x509.ParsePKCS1PrivateKey(block.Bytes)
 86→	case "EC PRIVATE KEY":
 87→		return x509.ParseECPrivateKey(block.Bytes)
 88→	default:
 89→		return nil, fmt.Errorf("unsupported key type: %s", block.Type)
 90→	}
 91→}
