 93→func parseCertPEMBytes(data []byte) (*x509.Certificate, error) {
 94→	block, _ := pem.Decode(data)
 95→	if block == nil {
 96→		return nil, fmt.Errorf("failed to decode certificate PEM")
 97→	}
 98→	return x509.ParseCertificate(block.Bytes)
 99→}
