23→func newCSRInspectCmd() *cobra.Command {
24→	cmd := &cobra.Command{
25→		Use:   "inspect [file]",
26→		Short: "Display CSR details",
27→		Long:  "Inspect a certificate signing request from a PEM file or stdin (-).",
