35→func runCSRInspect(args []string) error {
36→	if len(args) == 0 {
37→		return fmt.Errorf("provide a CSR file path or '-' for stdin")
38→	}
39→
40→	var data []byte
41→	var err error
42→	if args[0] == "-" {
43→		data, err = io.ReadAll(os.Stdin)
44→	} else {
45→		data, err = os.ReadFile(args[0])
46→	}
47→	if err != nil {
48→		return fmt.Errorf("reading input: %w", err)
49→	}
50→
51→	block, _ := pem.Decode(data)
52→	if block == nil {
53→		return fmt.Errorf("failed to decode PEM")
54→	}
55→
56→	csr, err := x509.ParseCertificateRequest(block.Bytes)
57→	if err != nil {
58→		return fmt.Errorf("parsing CSR: %w", err)
59→	}
60→
61→	if err := csr.CheckSignature(); err != nil {
62→		fmt.Printf("WARNING: CSR signature verification failed: %v\n", err)
63→	}
64→
65→	fmt.Printf("Subject:     %s\n", csr.Subject.String())
66→	if len(csr.DNSNames) > 0 {
67→		fmt.Printf("DNS SANs:    %s\n", strings.Join(csr.DNSNames, ", "))
68→	}
69→	if len(csr.IPAddresses) > 0 {
70→		ips := make([]string, len(csr.IPAddresses))
71→		for i, ip := range csr.IPAddresses {
72→			ips[i] = ip.String()
73→		}
74→		fmt.Printf("IP SANs:     %s\n", strings.Join(ips, ", "))
75→	}
76→	fmt.Printf("Public Key:  %s\n", csr.PublicKeyAlgorithm.String())
77→	fmt.Printf("Signature:   %s\n", csr.SignatureAlgorithm.String())
78→
79→	return nil
80→}
