 53→			return runCertIssue(cmd.Context(), cn, db, ca, days, san, keyAlgo, keySize, curve)
 54→		},
 55→	}
 56→
 57→	cmd.Flags().StringVar(&cn, "cn", "", "Common name for the certificate (required)")
 58→	cmd.Flags().StringVar(&db, "db", "gossl.db", "Path to the SQLite database file")
 59→	cmd.Flags().StringVar(&ca, "ca", "", "Signing CA common name (defaults to root CA)")
 60→	cmd.Flags().IntVar(&days, "days", 365, "Validity period in days")
 61→	cmd.Flags().StringVar(&san, "san", "", "Subject alternative names (comma-separated)")
 62→	cmd.Flags().StringVar(&keyAlgo, "key-algo", "rsa", "Key algorithm (rsa or ecdsa)")
 63→	cmd.Flags().IntVar(&keySize, "key-size", 4096, "RSA key size in bits")
 64→	cmd.Flags().StringVar(&curve, "curve", "P-256", "ECDSA curve (P-256, P-384, P-521)")
 65→	_ = cmd.MarkFlagRequired("cn")
 66→
 67→	return cmd
