 69→
 70→func runCertIssue(ctx context.Context, cn, dbPath, caCN string, days int, san, keyAlgo string, keySize int, curve string) error {
 71→	d, err := store.OpenDB(ctx, dbPath)
 72→	if err != nil {
 73→		return err
 74→	}
 75→	defer d.Close()
 76→
 77→	q := store.New(d.SqlDB())
 78→
 79→	var caRow store.Ca
 80→	if caCN == "" {
 81→		caRow, err = q.GetRootCA(ctx)
 82→		if err != nil {
 83→			return fmt.Errorf("no root CA found (use --ca to specify)")
 84→		}
 85→	} else {
 86→		caRow, err = q.GetCAByCN(ctx, caCN)
 87→		if err != nil {
 88→			return fmt.Errorf("CA %q not found", caCN)
 89→		}
 90→	}
 91→
 92→	caCert, err := parseCertPEMBytes([]byte(caRow.CertPem))
 93→	if err != nil {
 94→		return fmt.Errorf("parsing CA certificate: %w", err)
 95→	}
 96→
 97→	caKeyPEM, err := q.LoadKey(ctx, caRow.Serial)
 98→	if err != nil {
 99→		return fmt.Errorf("loading CA private key: %w", err)
100→	}
101→
102→	caKey, err := parsePrivateKey(caKeyPEM)
103→	if err != nil {
104→		return fmt.Errorf("parsing CA private key: %w", err)
105→	}
106→
107→	privKey, keyPEM, err := generateKey(keyAlgo, keySize, curve)
108→	if err != nil {
109→		return err
110→	}
111→
112→	serialNumber, err := generateSerial()
113→	if err != nil {
114→		return fmt.Errorf("generating serial number: %w", err)
115→	}
116→
117→	now := time.Now()
118→	template := &x509.Certificate{
119→		SerialNumber: serialNumber,
120→		Subject:      pkix.Name{CommonName: cn},
121→		NotBefore:    now,
122→		NotAfter:     now.AddDate(0, 0, days),
123→		KeyUsage:     x509.KeyUsageDigitalSignature | x509.KeyUsageKeyEncipherment,
124→		ExtKeyUsage:  []x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth, x509.ExtKeyUsageClientAuth},
125→	}
126→
127→	if san != "" {
128→		for _, s := range strings.Split(san, ",") {
129→			s = strings.TrimSpace(s)
130→			if ip := net.ParseIP(s); ip != nil {
131→				template.IPAddresses = append(template.IPAddresses, ip)
132→			} else {
133→				template.DNSNames = append(template.DNSNames, s)
134→			}
135→		}
136→	}
137→
138→	pubKey := publicKey(privKey)
139→	certDER, err := x509.CreateCertificate(rand.Reader, template, caCert, pubKey, caKey)
140→	if err != nil {
141→		return fmt.Errorf("creating certificate: %w", err)
142→	}
143→
144→	certPEM := pem.EncodeToMemory(&pem.Block{Type: "CERTIFICATE", Bytes: certDER})
145→	serial := serialHex(serialNumber)
146→
147→	_, err = q.CreateCert(ctx, store.CreateCertParams{
148→		CaID:       caRow.ID,
149→		CommonName: cn,
150→		Serial:     serial,
151→		KeyAlgo:    keyAlgo,
152→		CertPem:    string(certPEM),
153→		NotBefore:  template.NotBefore,
154→		NotAfter:   template.NotAfter,
155→		CreatedAt:  now,
156→	})
157→	if err != nil {
158→		return fmt.Errorf("storing cert: %w", err)
159→	}
160→
161→	if err := q.StoreKey(ctx, store.StoreKeyParams{ID: serial, KeyPem: keyPEM}); err != nil {
162→		return fmt.Errorf("storing private key: %w", err)
163→	}
164→
165→	fmt.Printf("Issued certificate %q (serial %s) signed by %q\n", cn, serial, caRow.CommonName)
166→	return nil
167→}
