297→func runCertExport(ctx context.Context, serial, dbPath, out string, chain, force bool) error {
298→	if !force {
299→		if _, err := os.Stat(out); err == nil {
300→			return fmt.Errorf("file %s already exists (use --force to overwrite)", out)
301→		}
302→	}
303→
304→	d, err := store.OpenDB(ctx, dbPath)
305→	if err != nil {
306→		return err
307→	}
308→	defer d.Close()
309→
310→	q := store.New(d.SqlDB())
311→
312→	cert, err := q.GetCertBySerial(ctx, serial)
313→	if err != nil {
314→		return fmt.Errorf("certificate %s not found", serial)
315→	}
316→
317→	pemData := cert.CertPem
318→
319→	if chain {
320→		// Walk up the CA chain
321→		caID := cert.CaID
322→		for {
323→			caRow, err := q.GetCA(ctx, caID)
324→			if err != nil {
325→				break
326→			}
327→			pemData += caRow.CertPem
328→			if !caRow.ParentID.Valid {
329→				break // reached root
330→			}
331→			caID = caRow.ParentID.Int64
332→		}
333→	}
334→
335→	if err := os.WriteFile(out, []byte(pemData), 0644); err != nil {
336→		return fmt.Errorf("writing file: %w", err)
337→	}
338→
339→	fmt.Printf("Exported certificate %s to %s\n", serial, out)
340→	return nil
341→}
