405→func printCertInfo(cert *x509.Certificate) {
406→	fmt.Printf("Subject:     %s\n", cert.Subject.String())
407→	fmt.Printf("Issuer:      %s\n", cert.Issuer.String())
408→	fmt.Printf("Serial:      %X\n", cert.SerialNumber)
409→	fmt.Printf("Not Before:  %s\n", cert.NotBefore.Format(time.RFC3339))
410→	fmt.Printf("Not After:   %s\n", cert.NotAfter.Format(time.RFC3339))
411→	fmt.Printf("Is CA:       %v\n", cert.IsCA)
412→
413→	if len(cert.DNSNames) > 0 {
414→		fmt.Printf("DNS SANs:    %s\n", strings.Join(cert.DNSNames, ", "))
415→	}
416→	if len(cert.IPAddresses) > 0 {
417→		ips := make([]string, len(cert.IPAddresses))
418→		for i, ip := range cert.IPAddresses {
419→			ips[i] = ip.String()
420→		}
421→		fmt.Printf("IP SANs:     %s\n", strings.Join(ips, ", "))
422→	}
423→
424→	if cert.PublicKeyAlgorithm != x509.UnknownPublicKeyAlgorithm {
425→		fmt.Printf("Public Key:  %s\n", cert.PublicKeyAlgorithm.String())
426→	}
427→
428→	fmt.Printf("Signature:   %s\n", cert.SignatureAlgorithm.String())
429→
430→	if now := time.Now(); now.After(cert.NotAfter) {
431→		fmt.Printf("Status:      EXPIRED (expired %s ago)\n", now.Sub(cert.NotAfter).Truncate(time.Hour))
432→	} else {
433→		fmt.Printf("Status:      valid (expires in %s)\n", cert.NotAfter.Sub(now).Truncate(time.Hour))
434→	}
435→}
