 1→// Package store provides SQLite-backed storage implementations.
 2→package store
 3→
 4→import (
 5→	"context"
 6→	"database/sql"
 7→	_ "embed"
 8→	"fmt"
 9→
10→	_ "modernc.org/sqlite"
11→)
12→
13→//go:embed migrations/001_init.sql
14→var schemaSQL string
15→
16→// SchemaVersion is the current database schema version.
17→const SchemaVersion = 1
18→
19→// DB wraps a sql.DB connection with schema management.
20→type DB struct {
21→	db *sql.DB
22→}
23→
24→// OpenDB opens a SQLite database and ensures the schema is initialized.
25→// Use ":memory:" for in-memory databases (testing).
26→func OpenDB(ctx context.Context, path string) (*DB, error) {
27→	sqlDB, err := sql.Open("sqlite", path)
28→	if err != nil {
29→		return nil, fmt.Errorf("opening database: %w", err)
30→	}
31→
32→	if err := sqlDB.PingContext(ctx); err != nil {
33→		sqlDB.Close()
34→		return nil, fmt.Errorf("connecting to database: %w", err)
35→	}
36→
37→	if _, err := sqlDB.ExecContext(ctx, "PRAGMA foreign_keys = ON"); err != nil {
38→		sqlDB.Close()
39→		return nil, fmt.Errorf("enabling foreign keys: %w", err)
40→	}
41→
42→	var version int
43→	if err := sqlDB.QueryRowContext(ctx, "PRAGMA user_version").Scan(&version); err != nil {
44→		sqlDB.Close()
45→		return nil, fmt.Errorf("reading schema version: %w", err)
46→	}
47→
48→	if version == 0 {
49→		if _, err := sqlDB.ExecContext(ctx, schemaSQL); err != nil {
50→			sqlDB.Close()
51→			return nil, fmt.Errorf("initializing schema: %w", err)
52→		}
53→		if _, err := sqlDB.ExecContext(ctx, fmt.Sprintf("PRAGMA user_version = %d", SchemaVersion)); err != nil {
54→			sqlDB.Close()
55→			return nil, fmt.Errorf("setting schema version: %w", err)
56→		}
57→	} else if version != SchemaVersion {
58→		sqlDB.Close()
59→		return nil, fmt.Errorf("unsupported schema version %d (expected %d)", version, SchemaVersion)
60→	}
61→
62→	return &DB{db: sqlDB}, nil
63→}
64→
65→// Close closes the underlying database connection.
66→func (d *DB) Close() error {
67→	return d.db.Close()
68→}
69→
70→// SqlDB returns the underlying *sql.DB for query execution.
71→func (d *DB) SqlDB() *sql.DB {
72→	return d.db
73→}
