 12→)
 13→
 14→func generateKey(algo string, size int, curve string) (any, []byte, error) {
 15→	switch algo {
 16→	case "rsa":
 17→		key, err := rsa.GenerateKey(rand.Reader, size)
 18→		if err != nil {
 19→			return nil, nil, fmt.Errorf("generating RSA key: %w", err)
 20→		}
 21→		keyPEM := pem.EncodeToMemory(&pem.Block{
 22→			Type:  "RSA PRIVATE KEY",
 23→			Bytes: x509.MarshalPKCS1PrivateKey(key),
 24→		})
 25→		return key, keyPEM, nil
 26→	case "ecdsa":
 27→		c, err := parseCurve(curve)
 28→		if err != nil {
 29→			return nil, nil, err
 30→		}
 31→		key, err := ecdsa.GenerateKey(c, rand.Reader)
 32→		if err != nil {
 33→			return nil, nil, fmt.Errorf("generating ECDSA key: %w", err)
 34→		}
 35→		der, err := x509.MarshalECPrivateKey(key)
 36→		if err != nil {
 37→			return nil, nil, fmt.Errorf("marshalling ECDSA key: %w", err)
 38→		}
 39→		keyPEM := pem.EncodeToMemory(&pem.Block{Type: "EC PRIVATE KEY", Bytes: der})
 40→		return key, keyPEM, nil
 41→	default:
 42→		return nil, nil, fmt.Errorf("unsupported key algorithm: %s", algo)
 43→	}
 44→}
 45→
 46→func parseCurve(name string) (elliptic.Curve, error) {
 47→	switch name {
 48→	case "P-256":
 49→		return elliptic.P256(), nil
 50→	case "P-384":
 51→		return elliptic.P384(), nil
 52→	case "P-521":
 53→		return elliptic.P521(), nil
 54→	default:
 55→		return nil, fmt.Errorf("unsupported curve: %s", name)
 56→	}
 57→}
 58→
 59→func publicKey(priv any) any {
 60→	switch k := priv.(type) {
 61→	case *rsa.PrivateKey:
 62→		return &k.PublicKey
 63→	case *ecdsa.PrivateKey:
 64→		return &k.PublicKey
 65→	default:
 66→		return nil
 67→	}
 68→}
 69→
 70→func generateSerial() (*big.Int, error) {
 71→	return rand.Int(rand.Reader, new(big.Int).Lsh(big.NewInt(1), 128))
 72→}
 73→
 74→func serialHex(sn *big.Int) string {
 75→	return fmt.Sprintf("%X", sn)
 76→}
 77→
 78→func parsePrivateKey(keyPEM []byte) (any, error) {
 79→	block, _ := pem.Decode(keyPEM)
 80→	if block == nil {
 81→		return nil, fmt.Errorf("failed to decode PEM")
 82→	}
 83→	switch block.Type {
 84→	case "RSA PRIVATE KEY":
 85→		return x509.ParsePKCS1PrivateKey(block.Bytes)
 86→	case "EC PRIVATE KEY":
 87→		return x509.ParseECPrivateKey(block.Bytes)
 88→	default:
 89→		return nil, fmt.Errorf("unsupported key type: %s", block.Type)
 90→	}
 91→}
 92→
 93→func parseCertPEMBytes(data []byte) (*x509.Certificate, error) {
 94→	block, _ := pem.Decode(data)
 95→	if block == nil {
 96→		return nil, fmt.Errorf("failed to decode certificate PEM")
 97→	}
 98→	return x509.ParseCertificate(block.Bytes)
 99→}
