14→func newCSRCmd() *cobra.Command {
15→	cmd := &cobra.Command{
16→		Use:   "csr",
17→		Short: "Inspect certificate signing requests",
18→	}
19→	cmd.AddCommand(newCSRInspectCmd())
20→	return cmd
