 24→func newServerCheckCmd() *cobra.Command {
 25→	var (
 26→		sni     string
 27→		timeout time.Duration
 28→		caFile  string
 29→	)
 30→
 31→	cmd := &cobra.Command{
 32→		Use:   "check <host:port>",
 33→		Short: "Check a server's TLS certificate chain",
 34→		Args:  cobra.ExactArgs(1),
 35→		RunE: func(cmd *cobra.Command, args []string) error {
 36→			return runServerCheck(args[0], sni, timeout, caFile)
 37→		},
 38→	}
 39→
 40→	cmd.Flags().StringVar(&sni, "sni", "", "Server name indication override")
 41→	cmd.Flags().DurationVar(&timeout, "timeout", 10*time.Second, "Connection timeout")
 42→	cmd.Flags().StringVar(&caFile, "ca-file", "", "Custom CA bundle for verification")
 43→
 44→	return cmd
