 47→func runServerCheck(addr, sni string, timeout time.Duration, caFile string) error {
 48→	if !strings.Contains(addr, ":") {
 49→		addr += ":443"
 50→	}
 51→
 52→	serverName := sni
 53→	if serverName == "" {
 54→		host, _, _ := strings.Cut(addr, ":")
 55→		serverName = host
 56→	}
 57→
 58→	tlsConf := &tls.Config{
 59→		ServerName:         serverName,
 60→		InsecureSkipVerify: true,
 61→	}
 62→
 63→	conn, err := tls.DialWithDialer(
 64→		&net.Dialer{Timeout: timeout},
 65→		"tcp", addr, tlsConf,
 66→	)
 67→	if err != nil {
 68→		return fmt.Errorf("connecting to %s: %w", addr, err)
 69→	}
 70→	defer conn.Close()
 71→
 72→	state := conn.ConnectionState()
 73→
 74→	fmt.Printf("Connected to %s (TLS %s)\n\n", addr, tlsVersionString(state.Version))
 75→
 76→	for i, cert := range state.PeerCertificates {
 77→		prefix := "  "
 78→		if i == 0 {
 79→			fmt.Printf("Server Certificate:\n")
 80→		} else {
 81→			fmt.Printf("Chain Certificate [%d]:\n", i)
 82→		}
 83→		fmt.Printf("%sSubject:     %s\n", prefix, cert.Subject.String())
 84→		fmt.Printf("%sIssuer:      %s\n", prefix, cert.Issuer.String())
 85→		fmt.Printf("%sSerial:      %X\n", prefix, cert.SerialNumber)
 86→		fmt.Printf("%sNot Before:  %s\n", prefix, cert.NotBefore.Format(time.RFC3339))
 87→		fmt.Printf("%sNot After:   %s\n", prefix, cert.NotAfter.Format(time.RFC3339))
 88→		fmt.Printf("%sIs CA:       %v\n", prefix, cert.IsCA)
 89→
 90→		if len(cert.DNSNames) > 0 {
 91→			fmt.Printf("%sDNS SANs:    %s\n", prefix, strings.Join(cert.DNSNames, ", "))
 92→		}
 93→
 94→		now := time.Now()
 95→		if now.After(cert.NotAfter) {
 96→			fmt.Printf("%sStatus:      EXPIRED\n", prefix)
 97→		} else if now.Before(cert.NotBefore) {
 98→			fmt.Printf("%sStatus:      NOT YET VALID\n", prefix)
 99→		} else {
100→			fmt.Printf("%sStatus:      valid (expires in %s)\n", prefix, cert.NotAfter.Sub(now).Truncate(time.Hour))
101→		}
102→		fmt.Println()
103→	}
104→
105→	// Verify chain
106→	var roots *x509.CertPool
107→	if caFile != "" {
108→		data, err := os.ReadFile(caFile)
109→		if err != nil {
110→			return fmt.Errorf("reading CA file: %w", err)
111→		}
112→		roots = x509.NewCertPool()
113→		roots.AppendCertsFromPEM(data)
114→	}
115→
116→	if len(state.PeerCertificates) > 0 {
117→		intermediates := x509.NewCertPool()
118→		for _, cert := range state.PeerCertificates[1:] {
119→			intermediates.AddCert(cert)
120→		}
121→
122→		opts := x509.VerifyOptions{
123→			Roots:         roots,
124→			Intermediates: intermediates,
125→			DNSName:       serverName,
126→		}
127→
128→		_, err := state.PeerCertificates[0].Verify(opts)
129→		if err != nil {
130→			fmt.Printf("Chain verification: FAILED (%v)\n", err)
131→		} else {
132→			fmt.Printf("Chain verification: OK\n")
133→		}
134→	}
135→
136→	return nil
137→}
138→
139→func tlsVersionString(v uint16) string {
140→	switch v {
141→	case tls.VersionTLS10:
142→		return "1.0"
143→	case tls.VersionTLS11:
144→		return "1.1"
145→	case tls.VersionTLS12:
146→		return "1.2"
147→	case tls.VersionTLS13:
148→		return "1.3"
149→	default:
150→		return fmt.Sprintf("unknown (0x%04x)", v)
151→	}
152→}
