437→// --- cert verify ---
438→
439→func newCertVerifyCmd() *cobra.Command {
440→	var chainFile string
441→
442→	cmd := &cobra.Command{
443→		Use:   "verify [file]",
444→		Short: "Verify a certificate against a CA bundle",
445→		RunE: func(cmd *cobra.Command, args []string) error {
446→			return runCertVerify(args, chainFile)
447→		},
448→	}
449→
450→	cmd.Flags().StringVar(&chainFile, "chain", "", "CA bundle PEM file (required)")
451→	_ = cmd.MarkFlagRequired("chain")
452→
453→	return cmd
454→}
455→
456→func runCertVerify(args []string, chainFile string) error {
457→	if len(args) == 0 {
458→		return fmt.Errorf("provide a certificate file path or '-' for stdin")
459→	}
460→
461→	var certData []byte
462→	var err error
463→	if args[0] == "-" {
464→		certData, err = io.ReadAll(os.Stdin)
465→	} else {
466→		certData, err = os.ReadFile(args[0])
467→	}
468→	if err != nil {
469→		return fmt.Errorf("reading certificate: %w", err)
470→	}
471→
472→	chainData, err := os.ReadFile(chainFile)
473→	if err != nil {
474→		return fmt.Errorf("reading chain file: %w", err)
475→	}
476→
477→	cert, err := parseCertPEMBytes(certData)
478→	if err != nil {
479→		return fmt.Errorf("parsing certificate: %w", err)
480→	}
481→
482→	roots := x509.NewCertPool()
483→	intermediates := x509.NewCertPool()
484→
485→	rest := chainData
486→	for {
487→		var block *pem.Block
488→		block, rest = pem.Decode(rest)
489→		if block == nil {
490→			break
491→		}
492→		chainCert, err := x509.ParseCertificate(block.Bytes)
493→		if err != nil {
494→			continue
495→		}
496→		if chainCert.IsCA && chainCert.Subject.String() == chainCert.Issuer.String() {
497→			roots.AddCert(chainCert)
498→		} else {
499→			intermediates.AddCert(chainCert)
500→		}
501→	}
502→
503→	_, err = cert.Verify(x509.VerifyOptions{
504→		Roots:         roots,
505→		Intermediates: intermediates,
506→	})
507→	if err != nil {
508→		return fmt.Errorf("verification failed: %w", err)
509→	}
510→
511→	fmt.Printf("OK: certificate %q verified successfully\n", cert.Subject.CommonName)
512→	return nil
513→}
