351→func buildMTLSClient(t *testing.T, caBundlePath, certPath, keyPath string) *http.Client {
352→	t.Helper()
353→
354→	clientCert, err := tls.LoadX509KeyPair(certPath, keyPath)
355→	if err != nil {
356→		t.Fatalf("LoadX509KeyPair: %v", err)
357→	}
358→
359→	rootCAs := x509.NewCertPool()
360→	caPEM, err := os.ReadFile(caBundlePath)
361→	if err != nil {
362→		t.Fatalf("reading CA bundle: %v", err)
363→	}
364→	rootCAs.AppendCertsFromPEM(caPEM)
365→
366→	return &http.Client{
367→		Transport: &http.Transport{
368→			TLSClientConfig: &tls.Config{
369→				Certificates: []tls.Certificate{clientCert},
370→				RootCAs:      rootCAs,
371→				ServerName:   "localhost",
372→			},
373→		},
374→		Timeout: 5 * time.Second,
375→	}
376→}
