 15→func TestCACreate_RootRSA(t *testing.T) {
 16→	dbPath := filepath.Join(t.TempDir(), "test.db")
 17→
 18→	err := runCACreate(context.Background(), "Test RSA CA", dbPath, "", 365, "rsa", 2048, "")
 19→	if err != nil {
 20→		t.Fatalf("runCACreate() error = %v", err)
 21→	}
 22→
 23→	ca, key := loadRootCAFromDB(t, dbPath)
 24→	if ca.CommonName != "Test RSA CA" {
 25→		t.Errorf("CommonName = %q, want %q", ca.CommonName, "Test RSA CA")
 26→	}
 27→	if ca.KeyAlgo != "rsa" {
 28→		t.Errorf("KeyAlgo = %q, want %q", ca.KeyAlgo, "rsa")
 29→	}
 30→	if ca.ParentID.Valid {
 31→		t.Error("Root CA ParentID should not be valid")
 32→	}
 33→
 34→	cert := parseCertPEMFromString(t, ca.CertPem)
 35→	if !cert.IsCA {
 36→		t.Error("cert.IsCA = false, want true")
 37→	}
 38→	if cert.Subject.CommonName != "Test RSA CA" {
 39→		t.Errorf("cert.Subject.CommonName = %q, want %q", cert.Subject.CommonName, "Test RSA CA")
 40→	}
 41→	if err := cert.CheckSignatureFrom(cert); err != nil {
 42→		t.Errorf("self-signed verification failed: %v", err)
 43→	}
 44→
 45→	block, _ := pem.Decode(key)
 46→	if block == nil {
 47→		t.Fatal("key PEM decode failed")
 48→	}
 49→	if block.Type != "RSA PRIVATE KEY" {
 50→		t.Errorf("key PEM type = %q, want %q", block.Type, "RSA PRIVATE KEY")
 51→	}
 52→	rsaKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
 53→	if err != nil {
 54→		t.Fatalf("ParsePKCS1PrivateKey error = %v", err)
 55→	}
 56→	if rsaKey.N.BitLen() != 2048 {
 57→		t.Errorf("RSA key size = %d, want 2048", rsaKey.N.BitLen())
 58→	}
 59→}
