 23→// TestMTLS_NginxWithGoSSLCerts creates a full CA hierarchy with gossl,
 24→// starts an nginx container with mTLS, and verifies client cert auth works.
 25→func TestMTLS_NginxWithGoSSLCerts(t *testing.T) {
 26→	ctx := context.Background()
 27→	tmpDir := t.TempDir()
 28→	dbPath := filepath.Join(tmpDir, "test.db")
 29→
 30→	// --- Build CA hierarchy and certs via CLI ---
 31→	root := cli.NewRoot()
 32→
 33→	run := func(args ...string) {
 34→		t.Helper()
 35→		cmd := cli.NewRoot()
 36→		cmd.SetArgs(args)
 37→		if err := cmd.Execute(); err != nil {
 38→			t.Fatalf("gossl %v: %v", args, err)
 39→		}
 40→	}
 41→
 42→	_ = root // suppress unused
 43→
 44→	run("ca", "create", "--cn", "Test Root CA", "--db", dbPath, "--key-size", "2048")
 45→	run("ca", "create", "--cn", "Test Intermediate", "--db", dbPath, "--key-size", "2048")
 46→	run("cert", "issue", "--cn", "localhost", "--ca", "Test Intermediate",
 47→		"--san", "localhost,127.0.0.1", "--db", dbPath, "--key-size", "2048")
 48→
 49→	// Export server cert chain and key
 50→	serverCertPath := filepath.Join(tmpDir, "server.pem")
 51→	serverKeyPath := filepath.Join(tmpDir, "server-key.pem")
 52→	caBundlePath := filepath.Join(tmpDir, "ca-bundle.pem")
 53→
 54→	// Get the cert serial from the DB
 55→	certSerial := getCertSerial(t, dbPath, "localhost")
 56→
 57→	run("cert", "export", "--serial", certSerial, "--db", dbPath, "--out", serverCertPath, "--chain")
 58→
 59→	// Export server private key
 60→	exportKey(t, dbPath, certSerial, serverKeyPath)
 61→
 62→	// Export CA bundle (root + intermediate) for client verification
 63→	exportCABundle(t, dbPath, caBundlePath)
 64→
 65→	// Generate client cert for mTLS
 66→	run("cert", "issue", "--cn", "test-client", "--ca", "Test Intermediate",
 67→		"--db", dbPath, "--key-size", "2048")
 68→	clientSerial := getCertSerial(t, dbPath, "test-client")
 69→	clientCertPath := filepath.Join(tmpDir, "client.pem")
 70→	clientKeyPath := filepath.Join(tmpDir, "client-key.pem")
 71→	run("cert", "export", "--serial", clientSerial, "--db", dbPath, "--out", clientCertPath, "--chain")
 72→	exportKey(t, dbPath, clientSerial, clientKeyPath)
 73→
 74→	// --- Write nginx config ---
 75→	nginxConf := filepath.Join(tmpDir, "nginx.conf")
 76→	writeFile(t, nginxConf, `
 77→events {}
 78→http {
 79→    server {
 80→        listen 443 ssl;
 81→        ssl_certificate /etc/nginx/certs/server.pem;
 82→        ssl_certificate_key /etc/nginx/certs/server-key.pem;
 83→        ssl_client_certificate /etc/nginx/certs/ca-bundle.pem;
 84→        ssl_verify_client on;
 85→
 86→        location / {
 87→            return 200 "mTLS OK: $ssl_client_s_dn\n";
 88→            add_header Content-Type text/plain;
 89→        }
 90→    }
 91→}
 92→`)
 93→
 94→	// --- Start nginx container ---
 95→	req := testcontainers.ContainerRequest{
 96→		Image:        "nginx:alpine",
 97→		ExposedPorts: []string{"443/tcp"},
 98→		WaitingFor:   wait.ForListeningPort("443/tcp").WithStartupTimeout(30 * time.Second),
 99→		Files: []testcontainers.ContainerFile{
100→			{HostFilePath: serverCertPath, ContainerFilePath: "/etc/nginx/certs/server.pem"},
101→			{HostFilePath: serverKeyPath, ContainerFilePath: "/etc/nginx/certs/server-key.pem"},
102→			{HostFilePath: caBundlePath, ContainerFilePath: "/etc/nginx/certs/ca-bundle.pem"},
103→			{HostFilePath: nginxConf, ContainerFilePath: "/etc/nginx/nginx.conf"},
104→		},
105→	}
106→
107→	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
108→		ContainerRequest: req,
109→		Started:          true,
110→	})
111→	if err != nil {
112→		t.Fatalf("starting nginx container: %v", err)
113→	}
114→	defer container.Terminate(ctx)
115→
116→	mappedPort, err := container.MappedPort(ctx, "443")
117→	if err != nil {
118→		t.Fatalf("getting mapped port: %v", err)
119→	}
120→
121→	host, err := container.Host(ctx)
122→	if err != nil {
123→		t.Fatalf("getting host: %v", err)
124→	}
125→
126→	addr := fmt.Sprintf("https://%s:%s", host, mappedPort.Port())
127→
128→	// --- Test 1: mTLS connection with valid client cert ---
129→	t.Run("valid_client_cert", func(t *testing.T) {
130→		client := buildMTLSClient(t, caBundlePath, clientCertPath, clientKeyPath)
131→		resp, err := client.Get(addr)
132→		if err != nil {
133→			t.Fatalf("GET %s: %v", addr, err)
134→		}
135→		defer resp.Body.Close()
136→
137→		if resp.StatusCode != http.StatusOK {
138→			t.Errorf("status = %d, want 200", resp.StatusCode)
139→		}
140→
141→		body, _ := io.ReadAll(resp.Body)
142→		t.Logf("Response: %s", body)
143→	})
144→
145→	// --- Test 2: Connection without client cert should fail ---
146→	t.Run("no_client_cert", func(t *testing.T) {
147→		rootCAs := x509.NewCertPool()
148→		caPEM, _ := os.ReadFile(caBundlePath)
149→		rootCAs.AppendCertsFromPEM(caPEM)
150→
151→		client := &http.Client{
152→			Transport: &http.Transport{
153→				TLSClientConfig: &tls.Config{
154→					RootCAs: rootCAs,
155→				},
156→			},
157→			Timeout: 5 * time.Second,
158→		}
159→
160→		_, err := client.Get(addr)
161→		if err == nil {
162→			t.Fatal("expected TLS error without client cert, got nil")
163→		}
164→		t.Logf("Expected error: %v", err)
165→	})
166→
167→	// --- Test 3: Verify cert chain with gossl cert verify ---
168→	t.Run("cert_verify", func(t *testing.T) {
169→		cmd := cli.NewRoot()
170→		cmd.SetArgs([]string{"cert", "verify", clientCertPath, "--chain", caBundlePath})
171→		if err := cmd.Execute(); err != nil {
172→			t.Fatalf("cert verify: %v", err)
173→		}
174→	})
175→}
