285→
286→func getCertSerial(t *testing.T, dbPath, cn string) string {
287→	t.Helper()
288→	ctx := context.Background()
289→
290→	d, err := store.OpenDB(ctx, dbPath)
291→	if err != nil {
292→		t.Fatalf("OpenDB: %v", err)
293→	}
294→	defer d.Close()
295→
296→	q := store.New(d.SqlDB())
297→	cert, err := q.GetCertByCN(ctx, cn)
298→	if err != nil {
299→		t.Fatalf("GetCertByCN(%s): %v", cn, err)
300→	}
301→	return cert.Serial
302→}
303→
304→func exportKey(t *testing.T, dbPath, serial, outPath string) {
305→	t.Helper()
306→	ctx := context.Background()
307→
308→	d, err := store.OpenDB(ctx, dbPath)
309→	if err != nil {
310→		t.Fatalf("OpenDB: %v", err)
311→	}
312→	defer d.Close()
313→
314→	q := store.New(d.SqlDB())
315→	keyPEM, err := q.LoadKey(ctx, serial)
316→	if err != nil {
317→		t.Fatalf("LoadKey(%s): %v", serial, err)
318→	}
319→
320→	if err := os.WriteFile(outPath, keyPEM, 0600); err != nil {
321→		t.Fatalf("writing key: %v", err)
322→	}
323→}
324→
325→func exportCABundle(t *testing.T, dbPath, outPath string) {
326→	t.Helper()
327→	ctx := context.Background()
328→
329→	d, err := store.OpenDB(ctx, dbPath)
330→	if err != nil {
331→		t.Fatalf("OpenDB: %v", err)
332→	}
333→	defer d.Close()
334→
335→	q := store.New(d.SqlDB())
336→	cas, err := q.ListCAs(ctx)
337→	if err != nil {
338→		t.Fatalf("ListCAs: %v", err)
339→	}
340→
341→	var bundle string
342→	for _, ca := range cas {
343→		bundle += ca.CertPem
344→	}
345→
346→	if err := os.WriteFile(outPath, []byte(bundle), 0644); err != nil {
347→		t.Fatalf("writing CA bundle: %v", err)
348→	}
349→}
350→
351→func buildMTLSClient(t *testing.T, caBundlePath, certPath, keyPath string) *http.Client {
352→	t.Helper()
353→
354→	clientCert, err := tls.LoadX509KeyPair(certPath, keyPath)
355→	if err != nil {
356→		t.Fatalf("LoadX509KeyPair: %v", err)
357→	}
358→
359→	rootCAs := x509.NewCertPool()
360→	caPEM, err := os.ReadFile(caBundlePath)
361→	if err != nil {
362→		t.Fatalf("reading CA bundle: %v", err)
363→	}
364→	rootCAs.AppendCertsFromPEM(caPEM)
365→
366→	return &http.Client{
367→		Transport: &http.Transport{
368→			TLSClientConfig: &tls.Config{
369→				Certificates: []tls.Certificate{clientCert},
370→				RootCAs:      rootCAs,
371→				ServerName:   "localhost",
372→			},
373→		},
374→		Timeout: 5 * time.Second,
375→	}
376→}
377→
378→func writeFile(t *testing.T, path, content string) {
379→	t.Helper()
380→	if err := os.WriteFile(path, []byte(content), 0644); err != nil {
381→		t.Fatalf("writing %s: %v", path, err)
382→	}
383→}
