 16→func newServeCmd() *cobra.Command {
 17→	var (
 18→		db      string
 19→		dn      string
 20→		certF   string
 21→		pkeyF   string
 22→		port    int
 23→		mtls    bool
 24→		verbose bool
 25→	)
 26→
 27→	cmd := &cobra.Command{
 28→		Use:   "serve",
 29→		Short: "Start an HTTPS echo server",
 30→		RunE: func(cmd *cobra.Command, args []string) error {
 31→			if (db != "" && dn != "") && (certF != "" || pkeyF != "") {
 32→				return fmt.Errorf("--db/--dn and --cert/--pkey are mutually exclusive")
 33→			}
 34→			if certF != "" || pkeyF != "" {
 35→				if certF == "" || pkeyF == "" {
 36→					return fmt.Errorf("both --cert and --pkey are required")
 37→				}
 38→				return runServeFile(cmd.Context(), certF, pkeyF, port, mtls, verbose)
 39→			}
 40→			if dn == "" {
 41→				return fmt.Errorf("provide --dn (with --db) or --cert/--pkey")
 42→			}
 43→			return runServeDB(cmd.Context(), db, dn, port, mtls, verbose)
 44→		},
 45→	}
 46→
 47→	cmd.Flags().StringVar(&db, "db", "gossl.db", "Path to the SQLite database file")
 48→	cmd.Flags().StringVar(&dn, "dn", "", "Certificate common name from the database")
 49→	cmd.Flags().StringVar(&certF, "cert", "", "Certificate PEM file")
 50→	cmd.Flags().StringVar(&pkeyF, "pkey", "", "Private key PEM file")
 51→	cmd.Flags().IntVar(&port, "port", 8443, "Listen port")
 52→	cmd.Flags().BoolVar(&mtls, "mtls", false, "Require and verify client certificates")
 53→	cmd.Flags().BoolVarP(&verbose, "verbose", "v", false, "Include request headers in response")
 54→
 55→	return cmd
 56→}
 57→
 58→func runServeDB(ctx context.Context, dbPath, dn string, port int, mtls, verbose bool) error {
 59→	d, err := store.OpenDB(ctx, dbPath)
 60→	if err != nil {
 61→		return err
 62→	}
 63→	defer d.Close()
 64→
 65→	q := store.New(d.SqlDB())
 66→
 67→	certRow, err := q.GetCertByCN(ctx, dn)
 68→	if err != nil {
 69→		return fmt.Errorf("certificate %q not found", dn)
 70→	}
 71→
 72→	keyPEM, err := q.LoadKey(ctx, certRow.Serial)
 73→	if err != nil {
 74→		return fmt.Errorf("loading private key: %w", err)
 75→	}
 76→
 77→	tlsCert, err := tls.X509KeyPair([]byte(certRow.CertPem), keyPEM)
 78→	if err != nil {
 79→		return fmt.Errorf("loading TLS keypair: %w", err)
 80→	}
 81→
 82→	// Load all CAs for mTLS verification
 83→	var clientCAs *x509.CertPool
 84→	if mtls {
 85→		clientCAs = x509.NewCertPool()
 86→		cas, err := q.ListCAs(ctx)
 87→		if err == nil {
 88→			for _, c := range cas {
 89→				clientCAs.AppendCertsFromPEM([]byte(c.CertPem))
 90→			}
 91→		}
 92→	}
 93→
 94→	return startServer(tlsCert, clientCAs, port, mtls, verbose)
 95→}
 96→
 97→func runServeFile(_ context.Context, certFile, pkeyFile string, port int, mtls, verbose bool) error {
 98→	tlsCert, err := tls.LoadX509KeyPair(certFile, pkeyFile)
 99→	if err != nil {
100→		return fmt.Errorf("loading TLS keypair: %w", err)
101→	}
102→
103→	var clientCAs *x509.CertPool
104→	if mtls {
105→		clientCAs, err = x509.SystemCertPool()
106→		if err != nil {
107→			clientCAs = x509.NewCertPool()
108→		}
109→	}
110→
111→	return startServer(tlsCert, clientCAs, port, mtls, verbose)
112→}
113→
114→func startServer(cert tls.Certificate, clientCAs *x509.CertPool, port int, mtls, verbose bool) error {
115→	clientAuth := tls.NoClientCert
116→	if mtls {
117→		clientAuth = tls.RequireAndVerifyClientCert
118→	}
119→
120→	tlsConf := &tls.Config{
121→		Certificates: []tls.Certificate{cert},
122→		ClientAuth:   clientAuth,
123→		ClientCAs:    clientCAs,
124→	}
125→
126→	mux := http.NewServeMux()
127→	mux.HandleFunc("/", echoHandler(verbose))
128→
129→	server := &http.Server{
130→		Addr:      fmt.Sprintf(":%d", port),
131→		Handler:   mux,
132→		TLSConfig: tlsConf,
133→	}
134→
135→	fmt.Printf("Listening on https://0.0.0.0:%d", port)
136→	if mtls {
137→		fmt.Print(" (mTLS enabled)")
138→	}
139→	fmt.Println()
140→
141→	return server.ListenAndServeTLS("", "")
142→}
143→
144→type echoResponse struct {
145→	URI     string            `json:"uri"`
146→	Method  string            `json:"method"`
147→	Headers map[string]string `json:"headers,omitempty"`
148→	Form    map[string]string `json:"form,omitempty"`
149→	Body    string            `json:"body,omitempty"`
150→	Peer    *peerInfo         `json:"peer,omitempty"`
151→}
152→
153→type peerInfo struct {
154→	Subject string `json:"subject"`
155→	Issuer  string `json:"issuer"`
156→	Serial  string `json:"serial"`
157→	Expiry  string `json:"expiry"`
158→}
159→
160→func echoHandler(verbose bool) http.HandlerFunc {
161→	return func(w http.ResponseWriter, r *http.Request) {
162→		resp := echoResponse{
163→			URI:    r.RequestURI,
164→			Method: r.Method,
165→		}
166→
167→		if verbose {
168→			resp.Headers = make(map[string]string)
169→			for k, v := range r.Header {
170→				resp.Headers[k] = v[0]
171→			}
172→		}
173→
174→		if r.Method == http.MethodPost || r.Method == http.MethodPut {
175→			_ = r.ParseForm()
176→			if len(r.Form) > 0 {
177→				resp.Form = make(map[string]string)
178→				for k, v := range r.Form {
179→					resp.Form[k] = v[0]
180→				}
181→			}
182→		}
183→
184→		if r.TLS != nil && len(r.TLS.PeerCertificates) > 0 {
185→			peer := r.TLS.PeerCertificates[0]
186→			resp.Peer = &peerInfo{
187→				Subject: peer.Subject.String(),
188→				Issuer:  peer.Issuer.String(),
189→				Serial:  fmt.Sprintf("%X", peer.SerialNumber),
190→				Expiry:  peer.NotAfter.Format(time.RFC3339),
191→			}
192→		}
193→
194→		w.Header().Set("Content-Type", "application/json")
195→		json.NewEncoder(w).Encode(resp)
196→	}
197→}
