 23→// TestMTLS_NginxWithGoSSLCerts creates a full CA hierarchy with gossl,
 24→// starts an nginx container with mTLS, and verifies client cert auth works.
 25→func TestMTLS_NginxWithGoSSLCerts(t *testing.T) {
 26→	ctx := context.Background()
 27→	tmpDir := t.TempDir()
 28→	dbPath := filepath.Join(tmpDir, "test.db")
 29→
 30→	// --- Build CA hierarchy and certs via CLI ---
 31→	root := cli.NewRoot()
 32→
 33→	run := func(args ...string) {
