 35→		cmd := cli.NewRoot()
 36→		cmd.SetArgs(args)
 37→		if err := cmd.Execute(); err != nil {
 38→			t.Fatalf("gossl %v: %v", args, err)
 39→		}
 40→	}
 41→
 42→	_ = root // suppress unused
 43→
 44→	run("ca", "create", "--cn", "Test Root CA", "--db", dbPath, "--key-size", "2048")
 45→	run("ca", "create", "--cn", "Test Intermediate", "--db", dbPath, "--key-size", "2048")
 46→	run("cert", "issue", "--cn", "localhost", "--ca", "Test Intermediate",
 47→		"--san", "localhost,127.0.0.1", "--db", dbPath, "--key-size", "2048")
 48→
 49→	// Export server cert chain and key
 50→	serverCertPath := filepath.Join(tmpDir, "server.pem")
 51→	serverKeyPath := filepath.Join(tmpDir, "server-key.pem")
 52→	caBundlePath := filepath.Join(tmpDir, "ca-bundle.pem")
 53→
 54→	// Get the cert serial from the DB
 55→	certSerial := getCertSerial(t, dbPath, "localhost")
 56→
 57→	run("cert", "export", "--serial", certSerial, "--db", dbPath, "--out", serverCertPath, "--chain")
 58→
 59→	// Export server private key
 60→	exportKey(t, dbPath, certSerial, serverKeyPath)
 61→
 62→	// Export CA bundle (root + intermediate) for client verification
 63→	exportCABundle(t, dbPath, caBundlePath)
 64→
 65→	// Generate client cert for mTLS
 66→	run("cert", "issue", "--cn", "test-client", "--ca", "Test Intermediate",
 67→		"--db", dbPath, "--key-size", "2048")
 68→	clientSerial := getCertSerial(t, dbPath, "test-client")
 69→	clientCertPath := filepath.Join(tmpDir, "client.pem")
 70→	clientKeyPath := filepath.Join(tmpDir, "client-key.pem")
 71→	run("cert", "export", "--serial", clientSerial, "--db", dbPath, "--out", clientCertPath, "--chain")
 72→	exportKey(t, dbPath, clientSerial, clientKeyPath)
