 75→	nginxConf := filepath.Join(tmpDir, "nginx.conf")
 76→	writeFile(t, nginxConf, `
 77→events {}
 78→http {
 79→    server {
 80→        listen 443 ssl;
 81→        ssl_certificate /etc/nginx/certs/server.pem;
 82→        ssl_certificate_key /etc/nginx/certs/server-key.pem;
 83→        ssl_client_certificate /etc/nginx/certs/ca-bundle.pem;
 84→        ssl_verify_client on;
 85→
 86→        location / {
 87→            return 200 "mTLS OK: $ssl_client_s_dn\n";
 88→            add_header Content-Type text/plain;
 89→        }
 90→    }
 91→}
 92→`)
 93→
 94→	// --- Start nginx container ---
 95→	req := testcontainers.ContainerRequest{
 96→		Image:        "nginx:alpine",
 97→		ExposedPorts: []string{"443/tcp"},
 98→		WaitingFor:   wait.ForListeningPort("443/tcp").WithStartupTimeout(30 * time.Second),
 99→		Files: []testcontainers.ContainerFile{
