107→	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
108→		ContainerRequest: req,
109→		Started:          true,
110→	})
111→	if err != nil {
112→		t.Fatalf("starting nginx container: %v", err)
113→	}
114→	defer container.Terminate(ctx)
115→
116→	mappedPort, err := container.MappedPort(ctx, "443")
117→	if err != nil {
118→		t.Fatalf("getting mapped port: %v", err)
