 62→	cmd.Flags().StringVar(&keyAlgo, "key-algo", "rsa", "Key algorithm (rsa or ecdsa)")
 63→	cmd.Flags().IntVar(&keySize, "key-size", 4096, "RSA key size in bits")
 64→	cmd.Flags().StringVar(&curve, "curve", "P-256", "ECDSA curve (P-256, P-384, P-521)")
 65→	_ = cmd.MarkFlagRequired("cn")
