366→func runCertInspect(ctx context.Context, args []string, dbPath, serial string) error {
367→	var pemData []byte
368→
369→	if dbPath != "" && serial != "" {
370→		d, err := store.OpenDB(ctx, dbPath)
371→		if err != nil {
372→			return err
373→		}
