380→		}
381→		pemData = []byte(cert.CertPem)
382→	} else if len(args) > 0 {
383→		var err error
384→		if args[0] == "-" {
385→			pemData, err = io.ReadAll(os.Stdin)
386→		} else {
387→			pemData, err = os.ReadFile(args[0])
388→		}
389→		if err != nil {
