391→		}
392→	} else {
393→		return fmt.Errorf("provide a file path, '-' for stdin, or --db --serial")
394→	}
395→
396→	cert, err := parseCertPEMBytes(pemData)
397→	if err != nil {
398→		return err
399→	}
400→
401→	printCertInfo(cert)
402→	return nil
403→}
