func runCertRevoke(ctx context.Context, serial, dbPath string) error {
	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		return err
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	n, err := q.RevokeCert(ctx, store.RevokeCertParams{
