package cli

import (
	"crypto/tls"
	"crypto/x509"
	"fmt"
	"net"
	"os"
	"strings"
	"time"

	"github.com/spf13/cobra"
)

func newServerCmd() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "server",
		Short: "Probe remote TLS servers",
	}
	cmd.AddCommand(newServerCheckCmd())
	return cmd
}

func newServerCheckCmd() *cobra.Command {
	var (
		sni     string
		timeout time.Duration
		caFile  string
	)

	cmd := &cobra.Command{
		Use:   "check <host:port>",
		Short: "Check a server's TLS certificate chain",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			return runServerCheck(args[0], sni, timeout, caFile)
		},
	}

	cmd.Flags().StringVar(&sni, "sni", "", "Server name indication override")
	cmd.Flags().DurationVar(&timeout, "timeout", 10*time.Second, "Connection timeout")
	cmd.Flags().StringVar(&caFile, "ca-file", "", "Custom CA bundle for verification")

	return cmd
}

func runServerCheck(addr, sni string, timeout time.Duration, caFile string) error {
	if !strings.Contains(addr, ":") {
		addr += ":443"
	}

	serverName := sni
	if serverName == "" {
		host, _, _ := strings.Cut(addr, ":")
		serverName = host
	}

	tlsConf := &tls.Config{
		ServerName:         serverName,
		InsecureSkipVerify: true,
	}

	conn, err := tls.DialWithDialer(
		&net.Dialer{Timeout: timeout},
		"tcp", addr, tlsConf,
	)
	if err != nil {
		return fmt.Errorf("connecting to %s: %w", addr, err)
	}
	defer conn.Close()

	state := conn.ConnectionState()

	fmt.Printf("Connected to %s (TLS %s)\n\n", addr, tlsVersionString(state.Version))

	for i, cert := range state.PeerCertificates {
		prefix := "  "
		if i == 0 {
			fmt.Printf("Server Certificate:\n")
		} else {
			fmt.Printf("Chain Certificate [%d]:\n", i)
		}
		fmt.Printf("%sSubject:     %s\n", prefix, cert.Subject.String())
		fmt.Printf("%sIssuer:      %s\n", prefix, cert.Issuer.String())
		fmt.Printf("%sSerial:      %X\n", prefix, cert.SerialNumber)
		fmt.Printf("%sNot Before:  %s\n", prefix, cert.NotBefore.Format(time.RFC3339))
		fmt.Printf("%sNot After:   %s\n", prefix, cert.NotAfter.Format(time.RFC3339))
		fmt.Printf("%sIs CA:       %v\n", prefix, cert.IsCA)

		if len(cert.DNSNames) > 0 {
			fmt.Printf("%sDNS SANs:    %s\n", prefix, strings.Join(cert.DNSNames, ", "))
		}

		now := time.Now()
		if now.After(cert.NotAfter) {
			fmt.Printf("%sStatus:      EXPIRED\n", prefix)
		} else if now.Before(cert.NotBefore) {
			fmt.Printf("%sStatus:      NOT YET VALID\n", prefix)
		} else {
			fmt.Printf("%sStatus:      valid (expires in %s)\n", prefix, cert.NotAfter.Sub(now).Truncate(time.Hour))
		}
		fmt.Println()
	}

	// Verify chain
	var roots *x509.CertPool
	if caFile != "" {
		data, err := os.ReadFile(caFile)
		if err != nil {
			return fmt.Errorf("reading CA file: %w", err)
		}
		roots = x509.NewCertPool()
		roots.AppendCertsFromPEM(data)
	}

	if len(state.PeerCertificates) > 0 {
		intermediates := x509.NewCertPool()
		for _, cert := range state.PeerCertificates[1:] {
			intermediates.AddCert(cert)
		}

		opts := x509.VerifyOptions{
			Roots:         roots,
			Intermediates: intermediates,
			DNSName:       serverName,
		}

		_, err := state.PeerCertificates[0].Verify(opts)
		if err != nil {
			fmt.Printf("Chain verification: FAILED (%v)\n", err)
		} else {
			fmt.Printf("Chain verification: OK\n")
		}
	}

	return nil
}

func tlsVersionString(v uint16) string {
	switch v {
	case tls.VersionTLS10:
		return "1.0"
	case tls.VersionTLS11:
		return "1.1"
	case tls.VersionTLS12:
		return "1.2"
	case tls.VersionTLS13:
		return "1.3"
	default:
		return fmt.Sprintf("unknown (0x%04x)", v)
	}
}

