// Package store provides SQLite-backed storage implementations.
package store

import (
	"context"
	"database/sql"
	_ "embed"
	"fmt"

	_ "modernc.org/sqlite"
)

//go:embed migrations/001_init.sql
var schemaSQL string

// SchemaVersion is the current database schema version.
const SchemaVersion = 1

// DB wraps a sql.DB connection with schema management.
type DB struct {
	db *sql.DB
}

// OpenDB opens a SQLite database and ensures the schema is initialized.
// Use ":memory:" for in-memory databases (testing).
func OpenDB(ctx context.Context, path string) (*DB, error) {
	sqlDB, err := sql.Open("sqlite", path)
	if err != nil {
		return nil, fmt.Errorf("opening database: %w", err)
	}

	if err := sqlDB.PingContext(ctx); err != nil {
		sqlDB.Close()
		return nil, fmt.Errorf("connecting to database: %w", err)
	}

	if _, err := sqlDB.ExecContext(ctx, "PRAGMA foreign_keys = ON"); err != nil {
		sqlDB.Close()
		return nil, fmt.Errorf("enabling foreign keys: %w", err)
	}

	var version int
	if err := sqlDB.QueryRowContext(ctx, "PRAGMA user_version").Scan(&version); err != nil {
		sqlDB.Close()
		return nil, fmt.Errorf("reading schema version: %w", err)
	}

	if version == 0 {
		if _, err := sqlDB.ExecContext(ctx, schemaSQL); err != nil {
			sqlDB.Close()
			return nil, fmt.Errorf("initializing schema: %w", err)
		}
		if _, err := sqlDB.ExecContext(ctx, fmt.Sprintf("PRAGMA user_version = %d", SchemaVersion)); err != nil {
			sqlDB.Close()
			return nil, fmt.Errorf("setting schema version: %w", err)
		}
	} else if version != SchemaVersion {
		sqlDB.Close()
		return nil, fmt.Errorf("unsupported schema version %d (expected %d)", version, SchemaVersion)
	}

	return &DB{db: sqlDB}, nil
}

// Close closes the underlying database connection.
func (d *DB) Close() error {
	return d.db.Close()
}

// SqlDB returns the underlying *sql.DB for query execution.
func (d *DB) SqlDB() *sql.DB {
	return d.db
}

package cli

import (
	"context"
	"crypto/tls"
	"crypto/x509"
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/bejelith/gossl/internal/store"
	"github.com/spf13/cobra"
)

func newServeCmd() *cobra.Command {
	var (
		db      string
		dn      string
		certF   string
		pkeyF   string
		port    int
		mtls    bool
		verbose bool
	)

	cmd := &cobra.Command{
		Use:   "serve",
		Short: "Start an HTTPS echo server",
		RunE: func(cmd *cobra.Command, args []string) error {
			if (db != "" && dn != "") && (certF != "" || pkeyF != "") {
				return fmt.Errorf("--db/--dn and --cert/--pkey are mutually exclusive")
			}
			if certF != "" || pkeyF != "" {
				if certF == "" || pkeyF == "" {
					return fmt.Errorf("both --cert and --pkey are required")
				}
				return runServeFile(cmd.Context(), certF, pkeyF, port, mtls, verbose)
			}
			if dn == "" {
				return fmt.Errorf("provide --dn (with --db) or --cert/--pkey")
			}
			return runServeDB(cmd.Context(), db, dn, port, mtls, verbose)
		},
	}

	cmd.Flags().StringVar(&db, "db", "gossl.db", "Path to the SQLite database file")
	cmd.Flags().StringVar(&dn, "dn", "", "Certificate common name from the database")
	cmd.Flags().StringVar(&certF, "cert", "", "Certificate PEM file")
	cmd.Flags().StringVar(&pkeyF, "pkey", "", "Private key PEM file")
	cmd.Flags().IntVar(&port, "port", 8443, "Listen port")
	cmd.Flags().BoolVar(&mtls, "mtls", false, "Require and verify client certificates")
	cmd.Flags().BoolVarP(&verbose, "verbose", "v", false, "Include request headers in response")

	return cmd
}

func runServeDB(ctx context.Context, dbPath, dn string, port int, mtls, verbose bool) error {
	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		return err
	}
	defer d.Close()

	q := store.New(d.SqlDB())

	certRow, err := q.GetCertByCN(ctx, dn)
	if err != nil {
		return fmt.Errorf("certificate %q not found", dn)
	}

	keyPEM, err := q.LoadKey(ctx, certRow.Serial)
	if err != nil {
		return fmt.Errorf("loading private key: %w", err)
	}

	tlsCert, err := tls.X509KeyPair([]byte(certRow.CertPem), keyPEM)
	if err != nil {
		return fmt.Errorf("loading TLS keypair: %w", err)
	}

	// Load all CAs for mTLS verification
	var clientCAs *x509.CertPool
	if mtls {
		clientCAs = x509.NewCertPool()
		cas, err := q.ListCAs(ctx)
		if err == nil {
