// TestMTLS_NginxWithGoSSLCerts creates a full CA hierarchy with gossl,
// starts an nginx container with mTLS, and verifies client cert auth works.
func TestMTLS_NginxWithGoSSLCerts(t *testing.T) {
	ctx := context.Background()
	tmpDir := t.TempDir()
	dbPath := filepath.Join(tmpDir, "test.db")

	// --- Build CA hierarchy and certs via CLI ---
	root := cli.NewRoot()

	run := func(args ...string) {
		t.Helper()
		cmd := cli.NewRoot()
		cmd.SetArgs(args)
		if err := cmd.Execute(); err != nil {
			t.Fatalf("gossl %v: %v", args, err)
		}
	}

	_ = root // suppress unused

	run("ca", "create", "--cn", "Test Root CA", "--db", dbPath, "--key-size", "2048")
	run("ca", "create", "--cn", "Test Intermediate", "--db", dbPath, "--key-size", "2048")
	run("cert", "issue", "--cn", "localhost", "--ca", "Test Intermediate",
		"--san", "localhost,127.0.0.1", "--db", dbPath, "--key-size", "2048")

	// Export server cert chain and key
	serverCertPath := filepath.Join(tmpDir, "server.pem")
	serverKeyPath := filepath.Join(tmpDir, "server-key.pem")
	caBundlePath := filepath.Join(tmpDir, "ca-bundle.pem")

	// Get the cert serial from the DB
	certSerial := getCertSerial(t, dbPath, "localhost")

	run("cert", "export", "--serial", certSerial, "--db", dbPath, "--out", serverCertPath, "--chain")

	// Export server private key
	exportKey(t, dbPath, certSerial, serverKeyPath)

	// Export CA bundle (root + intermediate) for client verification
	exportCABundle(t, dbPath, caBundlePath)

	// Generate client cert for mTLS
	run("cert", "issue", "--cn", "test-client", "--ca", "Test Intermediate",
		"--db", dbPath, "--key-size", "2048")
	clientSerial := getCertSerial(t, dbPath, "test-client")
	clientCertPath := filepath.Join(tmpDir, "client.pem")
	clientKeyPath := filepath.Join(tmpDir, "client-key.pem")
	run("cert", "export", "--serial", clientSerial, "--db", dbPath, "--out", clientCertPath, "--chain")
	exportKey(t, dbPath, clientSerial, clientKeyPath)

	// --- Write nginx config ---
	nginxConf := filepath.Join(tmpDir, "nginx.conf")
	writeFile(t, nginxConf, `
events {}
http {
    server {
        listen 443 ssl;
        ssl_certificate /etc/nginx/certs/server.pem;
        ssl_certificate_key /etc/nginx/certs/server-key.pem;
        ssl_client_certificate /etc/nginx/certs/ca-bundle.pem;
        ssl_verify_client on;

        location / {
            return 200 "mTLS OK: $ssl_client_s_dn\n";
            add_header Content-Type text/plain;
        }
    }
}
`)

	// --- Start nginx container ---
	req := testcontainers.ContainerRequest{
		Image:        "nginx:alpine",
		ExposedPorts: []string{"443/tcp"},
		WaitingFor:   wait.ForListeningPort("443/tcp").WithStartupTimeout(30 * time.Second),
		Files: []testcontainers.ContainerFile{
			{HostFilePath: serverCertPath, ContainerFilePath: "/etc/nginx/certs/server.pem"},
			{HostFilePath: serverKeyPath, ContainerFilePath: "/etc/nginx/certs/server-key.pem"},
			{HostFilePath: caBundlePath, ContainerFilePath: "/etc/nginx/certs/ca-bundle.pem"},
			{HostFilePath: nginxConf, ContainerFilePath: "/etc/nginx/nginx.conf"},
		},
	}

	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
		ContainerRequest: req,
		Started:          true,
	})
	if err != nil {
		t.Fatalf("starting nginx container: %v", err)
	}
	defer container.Terminate(ctx)

	mappedPort, err := container.MappedPort(ctx, "443")
	if err != nil {
		t.Fatalf("getting mapped port: %v", err)
	}

	host, err := container.Host(ctx)
	if err != nil {
		t.Fatalf("getting host: %v", err)
	}

	addr := fmt.Sprintf("https://%s:%s", host, mappedPort.Port())

	// --- Test 1: mTLS connection with valid client cert ---
	t.Run("valid_client_cert", func(t *testing.T) {
		client := buildMTLSClient(t, caBundlePath, clientCertPath, clientKeyPath)
		resp, err := client.Get(addr)
		if err != nil {
			t.Fatalf("GET %s: %v", addr, err)
		}
		defer resp.Body.Close()

		if resp.StatusCode != http.StatusOK {
			t.Errorf("status = %d, want 200", resp.StatusCode)
		}

		body, _ := io.ReadAll(resp.Body)
		t.Logf("Response: %s", body)
	})

	// --- Test 2: Connection without client cert should be rejected ---
	t.Run("no_client_cert", func(t *testing.T) {
		rootCAs := x509.NewCertPool()
		caPEM, _ := os.ReadFile(caBundlePath)
		rootCAs.AppendCertsFromPEM(caPEM)

		client := &http.Client{
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{
					RootCAs: rootCAs,
				},
			},
			Timeout: 5 * time.Second,
		}

		resp, err := client.Get(addr)
		if err != nil {
			// TLS handshake failure — expected
			t.Logf("Expected TLS error: %v", err)
			return
		}
		defer resp.Body.Close()

		// nginx may accept TLS but return 400 when client cert is missing
		if resp.StatusCode == http.StatusOK {
			t.Fatal("expected rejection without client cert, got 200 OK")
		}
		t.Logf("Rejected with HTTP %d (no client cert)", resp.StatusCode)
	})

	// --- Test 3: Verify cert chain with gossl cert verify ---
	t.Run("cert_verify", func(t *testing.T) {
		cmd := cli.NewRoot()
		cmd.SetArgs([]string{"cert", "verify", clientCertPath, "--chain", caBundlePath})
		if err := cmd.Execute(); err != nil {
			t.Fatalf("cert verify: %v", err)
		}
	})
}

