package cli

import (
	"context"
	"crypto/rand"
	"crypto/x509"
	"crypto/x509/pkix"
	"database/sql"
	"encoding/pem"
	"fmt"
	"time"

	"github.com/bejelith/gossl/internal/store"
	"github.com/spf13/cobra"
)

func newCACmd() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "ca",
		Short: "Manage certificate authorities",
	}
	cmd.AddCommand(newCACreateCmd())
	cmd.AddCommand(newCAListCmd())
	return cmd
}

func newCACreateCmd() *cobra.Command {
	var (
		cn      string
		db      string
		ca      string
		days    int
		keyAlgo string
		keySize int
		curve   string
	)

	cmd := &cobra.Command{
		Use:   "create",
		Short: "Create a root CA or intermediate CA",
		Long:  "Create a new CA. Without --ca, creates a self-signed root CA.\nWith --ca, creates an intermediate CA signed by the specified CA.",
		RunE: func(cmd *cobra.Command, args []string) error {
			return runCACreate(cmd.Context(), cn, db, ca, days, keyAlgo, keySize, curve)
		},
	}

	cmd.Flags().StringVar(&cn, "cn", "", "Common name for the CA (required)")
	cmd.Flags().StringVar(&db, "db", "gossl.db", "Path to the SQLite database file")
	cmd.Flags().StringVar(&ca, "ca", "", "Parent CA common name (omit for root CA)")
	cmd.Flags().IntVar(&days, "days", 3650, "Validity period in days")
	cmd.Flags().StringVar(&keyAlgo, "key-algo", "rsa", "Key algorithm (rsa or ecdsa)")
	cmd.Flags().IntVar(&keySize, "key-size", 4096, "RSA key size in bits")
	cmd.Flags().StringVar(&curve, "curve", "P-256", "ECDSA curve (P-256, P-384, P-521)")
	_ = cmd.MarkFlagRequired("cn")

	return cmd
}

func newCAListCmd() *cobra.Command {
	var db string

	cmd := &cobra.Command{
		Use:   "list",
		Short: "List all CAs",
		RunE: func(cmd *cobra.Command, args []string) error {
			return runCAList(cmd.Context(), db)
		},
	}

	cmd.Flags().StringVar(&db, "db", "gossl.db", "Path to the SQLite database file")
	return cmd
}

func runCACreate(ctx context.Context, cn, dbPath, parentCN string, days int, keyAlgo string, keySize int, curve string) error {
	privKey, keyPEM, err := generateKey(keyAlgo, keySize, curve)
	if err != nil {
		return err
	}

	serialNumber, err := generateSerial()
	if err != nil {
		return fmt.Errorf("generating serial number: %w", err)
	}

	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		return err
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	now := time.Now()
	pubKey := publicKey(privKey)

	var signerCert *x509.Certificate
	var signerKey any
	var parentID sql.NullInt64
	var maxPathLen int
	var label string

	if parentCN == "" {
		// Check if a root CA already exists — if so, default to it as parent
		existingRoot, rootErr := q.GetRootCA(ctx)
		if rootErr == nil {
			// Root exists — this is an intermediate defaulting to root
			parentCN = existingRoot.CommonName
		}
	}

	if parentCN == "" {
		// No root CA exists — self-signed root CA
		signerKey = privKey
		maxPathLen = 2
		label = "root CA"
	} else {
		// Intermediate — find parent
		parent, err := q.GetCAByCN(ctx, parentCN)
		if err != nil {
			return fmt.Errorf("parent CA %q not found", parentCN)
		}
		signerCert, err = parseCertPEMBytes([]byte(parent.CertPem))
		if err != nil {
			return fmt.Errorf("parsing parent certificate: %w", err)
		}
		parentKeyPEM, err := q.LoadKey(ctx, parent.Serial)
		if err != nil {
			return fmt.Errorf("loading parent private key: %w", err)
		}
		signerKey, err = parsePrivateKey(parentKeyPEM)
		if err != nil {
			return fmt.Errorf("parsing parent private key: %w", err)
		}
		parentID = sql.NullInt64{Int64: parent.ID, Valid: true}
		// Reduce maxPathLen from parent
		if signerCert.MaxPathLen > 0 {
			maxPathLen = signerCert.MaxPathLen - 1
		}
		label = fmt.Sprintf("intermediate CA (signed by %q)", parentCN)
	}

	template := &x509.Certificate{
		SerialNumber:          serialNumber,
		Subject:               pkix.Name{CommonName: cn},
		NotBefore:             now,
		NotAfter:              now.AddDate(0, 0, days),
		KeyUsage:              x509.KeyUsageCertSign | x509.KeyUsageCRLSign,
		BasicConstraintsValid: true,
		IsCA:                  true,
		MaxPathLen:            maxPathLen,
		MaxPathLenZero:        maxPathLen == 0,
	}

	// For root CA, self-sign
	if signerCert == nil {
		signerCert = template
	}

	certDER, err := x509.CreateCertificate(rand.Reader, template, signerCert, pubKey, signerKey)
	if err != nil {
		return fmt.Errorf("creating certificate: %w", err)
	}

	certPEM := pem.EncodeToMemory(&pem.Block{Type: "CERTIFICATE", Bytes: certDER})
	serial := serialHex(serialNumber)

	_, err = q.CreateCA(ctx, store.CreateCAParams{
		ParentID:   parentID,
		CommonName: cn,
		Serial:     serial,
		KeyAlgo:    keyAlgo,
		CertPem:    string(certPEM),
		NotBefore:  template.NotBefore,
		NotAfter:   template.NotAfter,
		CreatedAt:  now,
	})
	if err != nil {
		return fmt.Errorf("storing CA: %w", err)
	}

	if err := q.StoreKey(ctx, store.StoreKeyParams{ID: serial, KeyPem: keyPEM}); err != nil {
		return fmt.Errorf("storing private key: %w", err)
	}

	fmt.Printf("Created %s %q (serial %s) in %s\n", label, cn, serial, dbPath)
	return nil
}

func runCAList(ctx context.Context, dbPath string) error {
	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		return err
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	cas, err := q.ListCAs(ctx)
	if err != nil {
		return fmt.Errorf("listing CAs: %w", err)
	}

	if len(cas) == 0 {
		fmt.Println("No CAs found.")
		return nil
	}

	for _, c := range cas {
		kind := "Root CA"
		if c.ParentID.Valid {
			kind = "Intermediate CA"
		}
		fmt.Printf("%s:\n", kind)
		fmt.Printf("  Common Name: %s\n", c.CommonName)
		fmt.Printf("  Serial:      %s\n", c.Serial)
		fmt.Printf("  Algorithm:   %s\n", c.KeyAlgo)
		fmt.Printf("  Not Before:  %s\n", c.NotBefore.Format(time.RFC3339))
		fmt.Printf("  Not After:   %s\n", c.NotAfter.Format(time.RFC3339))
		fmt.Println()
	}
	return nil
}

package store

import (
	"context"
	"database/sql"
	"testing"
)

func openTestDB(t *testing.T) *DB {
	t.Helper()
	db, err := OpenDB(context.Background(), ":memory:")
	if err != nil {
		t.Fatalf("OpenDB(:memory:) error = %v", err)
	}
	t.Cleanup(func() { db.Close() })
	return db
}

func newTestQueries(t *testing.T) *Queries {
	t.Helper()
	db := openTestDB(t)
	return New(db.SqlDB())
}

func TestKeyStore_StoreAndLoad(t *testing.T) {
	q := newTestQueries(t)
	ctx := context.Background()

	key := []byte("-----BEGIN RSA PRIVATE KEY-----\ntest\n-----END RSA PRIVATE KEY-----")
	if err := q.StoreKey(ctx, StoreKeyParams{ID: "serial-001", KeyPem: key}); err != nil {
		t.Fatalf("StoreKey() error = %v", err)
	}

	got, err := q.LoadKey(ctx, "serial-001")
	if err != nil {
		t.Fatalf("LoadKey() error = %v", err)
	}
	if string(got) != string(key) {
		t.Errorf("LoadKey() = %q, want %q", got, key)
	}
}

func TestKeyStore_LoadNotFound(t *testing.T) {
	q := newTestQueries(t)
	ctx := context.Background()

	_, err := q.LoadKey(ctx, "nonexistent")
	if err != sql.ErrNoRows {
		t.Fatalf("LoadKey(nonexistent) error = %v, want sql.ErrNoRows", err)
	}
}

func TestKeyStore_Delete(t *testing.T) {
	q := newTestQueries(t)
	ctx := context.Background()

	key := []byte("test-key")
	if err := q.StoreKey(ctx, StoreKeyParams{ID: "serial-002", KeyPem: key}); err != nil {
		t.Fatalf("StoreKey() error = %v", err)
	}
	n, err := q.DeleteKey(ctx, "serial-002")
	if err != nil {
		t.Fatalf("DeleteKey() error = %v", err)
	}
	if n != 1 {
		t.Errorf("DeleteKey() rows = %d, want 1", n)
	}
	_, err = q.LoadKey(ctx, "serial-002")
	if err != sql.ErrNoRows {
		t.Fatalf("LoadKey() after Delete error = %v, want sql.ErrNoRows", err)
	}
}

func TestKeyStore_DeleteNotFound(t *testing.T) {
	q := newTestQueries(t)
	ctx := context.Background()

	n, err := q.DeleteKey(ctx, "nonexistent")
	if err != nil {
		t.Fatalf("DeleteKey(nonexistent) error = %v", err)
	}
	if n != 0 {
		t.Errorf("DeleteKey(nonexistent) rows = %d, want 0", n)
	}
}

func TestKeyStore_StoreDuplicate(t *testing.T) {
	q := newTestQueries(t)
	ctx := context.Background()

	key := []byte("test-key")
	if err := q.StoreKey(ctx, StoreKeyParams{ID: "serial-003", KeyPem: key}); err != nil {
		t.Fatalf("StoreKey() error = %v", err)
	}
	err := q.StoreKey(ctx, StoreKeyParams{ID: "serial-003", KeyPem: key})
	if err == nil {
		t.Fatal("StoreKey(duplicate) expected error, got nil")
	}
}

package cli

import (
	"context"
	"crypto/ecdsa"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"path/filepath"
	"testing"

	"github.com/bejelith/gossl/internal/store"
)

func TestCACreate_RootRSA(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	err := runCACreate(context.Background(), "Test RSA CA", dbPath, "", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("runCACreate() error = %v", err)
	}

	ca, key := loadRootCAFromDB(t, dbPath)
	if ca.CommonName != "Test RSA CA" {
		t.Errorf("CommonName = %q, want %q", ca.CommonName, "Test RSA CA")
	}
	if ca.KeyAlgo != "rsa" {
		t.Errorf("KeyAlgo = %q, want %q", ca.KeyAlgo, "rsa")
	}
	if ca.ParentID.Valid {
		t.Error("Root CA ParentID should not be valid")
	}

	cert := parseCertPEMFromString(t, ca.CertPem)
	if !cert.IsCA {
		t.Error("cert.IsCA = false, want true")
	}
	if cert.Subject.CommonName != "Test RSA CA" {
		t.Errorf("cert.Subject.CommonName = %q, want %q", cert.Subject.CommonName, "Test RSA CA")
	}
	if err := cert.CheckSignatureFrom(cert); err != nil {
		t.Errorf("self-signed verification failed: %v", err)
	}

	block, _ := pem.Decode(key)
	if block == nil {
		t.Fatal("key PEM decode failed")
	}
	if block.Type != "RSA PRIVATE KEY" {
		t.Errorf("key PEM type = %q, want %q", block.Type, "RSA PRIVATE KEY")
	}
	rsaKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		t.Fatalf("ParsePKCS1PrivateKey error = %v", err)
	}
	if rsaKey.N.BitLen() != 2048 {
		t.Errorf("RSA key size = %d, want 2048", rsaKey.N.BitLen())
	}
}

func TestCACreate_RootECDSA(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	err := runCACreate(context.Background(), "Test ECDSA CA", dbPath, "", 365, "ecdsa", 0, "P-384")
	if err != nil {
		t.Fatalf("runCACreate() error = %v", err)
	}

	ca, key := loadRootCAFromDB(t, dbPath)
	if ca.KeyAlgo != "ecdsa" {
		t.Errorf("KeyAlgo = %q, want %q", ca.KeyAlgo, "ecdsa")
	}

	cert := parseCertPEMFromString(t, ca.CertPem)
	if !cert.IsCA {
		t.Error("cert.IsCA = false, want true")
	}

	block, _ := pem.Decode(key)
	if block == nil {
		t.Fatal("key PEM decode failed")
	}
	ecKey, err := x509.ParseECPrivateKey(block.Bytes)
	if err != nil {
		t.Fatalf("ParseECPrivateKey error = %v", err)
	}
	if ecKey.Curve.Params().Name != "P-384" {
		t.Errorf("ECDSA curve = %q, want P-384", ecKey.Curve.Params().Name)
	}
}

func TestCACreate_IntermediateDefaultsToRoot(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	// Create root
	err := runCACreate(context.Background(), "Root CA", dbPath, "", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("root runCACreate() error = %v", err)
	}

	// Create intermediate without --ca — should default to root
	err = runCACreate(context.Background(), "Intermediate CA", dbPath, "", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("intermediate runCACreate() error = %v", err)
	}

	d, err := store.OpenDB(context.Background(), dbPath)
	if err != nil {
		t.Fatalf("OpenDB() error = %v", err)
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	intCA, err := q.GetCAByCN(context.Background(), "Intermediate CA")
	if err != nil {
		t.Fatalf("GetCAByCN() error = %v", err)
	}
	if !intCA.ParentID.Valid {
		t.Fatal("Intermediate CA should have a parent")
	}

	// Verify it's signed by root
	cert := parseCertPEMFromString(t, intCA.CertPem)
	if cert.Issuer.CommonName != "Root CA" {
		t.Errorf("intermediate issuer = %q, want %q", cert.Issuer.CommonName, "Root CA")
	}
}

func TestCACreate_IntermediateWithExplicitCA(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	err := runCACreate(context.Background(), "Root CA", dbPath, "", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("root error = %v", err)
	}

	err = runCACreate(context.Background(), "Level 1", dbPath, "Root CA", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("level1 error = %v", err)
	}

	// Create off Level 1
	err = runCACreate(context.Background(), "Level 2", dbPath, "Level 1", 365, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("level2 error = %v", err)
	}

	d, err := store.OpenDB(context.Background(), dbPath)
	if err != nil {
		t.Fatalf("OpenDB() error = %v", err)
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	l2, err := q.GetCAByCN(context.Background(), "Level 2")
	if err != nil {
		t.Fatalf("GetCAByCN() error = %v", err)
	}

	cert := parseCertPEMFromString(t, l2.CertPem)
	if cert.Issuer.CommonName != "Level 1" {
		t.Errorf("Level 2 issuer = %q, want %q", cert.Issuer.CommonName, "Level 1")
	}
}

func TestCACreate_InvalidAlgo(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")
	err := runCACreate(context.Background(), "Bad CA", dbPath, "", 365, "ed25519", 0, "")
	if err == nil {
		t.Fatal("runCACreate(ed25519) expected error, got nil")
	}
}

func TestCACreate_InvalidCurve(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")
	err := runCACreate(context.Background(), "Bad CA", dbPath, "", 365, "ecdsa", 0, "P-999")
	if err == nil {
		t.Fatal("runCACreate(P-999) expected error, got nil")
	}
}

func TestCACreate_CertProperties(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	err := runCACreate(context.Background(), "Prop CA", dbPath, "", 730, "rsa", 2048, "")
	if err != nil {
		t.Fatalf("runCACreate() error = %v", err)
	}

	ca, _ := loadRootCAFromDB(t, dbPath)
	cert := parseCertPEMFromString(t, ca.CertPem)

	if cert.KeyUsage&x509.KeyUsageCertSign == 0 {
		t.Error("cert missing KeyUsageCertSign")
	}
	if cert.KeyUsage&x509.KeyUsageCRLSign == 0 {
		t.Error("cert missing KeyUsageCRLSign")
	}

	duration := cert.NotAfter.Sub(cert.NotBefore)
	days := int(duration.Hours() / 24)
	if days < 729 || days > 731 {
		t.Errorf("validity = %d days, want ~730", days)
	}
}

func TestCACreate_CobraCommand(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "test.db")

	root := NewRoot()
	root.SetArgs([]string{"ca", "create", "--cn", "Cobra CA", "--db", dbPath, "--key-size", "2048"})
	if err := root.Execute(); err != nil {
		t.Fatalf("Execute() error = %v", err)
	}

	ca, _ := loadRootCAFromDB(t, dbPath)
	if ca.CommonName != "Cobra CA" {
		t.Errorf("CommonName = %q, want %q", ca.CommonName, "Cobra CA")
	}
}

func TestCACreate_CobraMissingCN(t *testing.T) {
	root := NewRoot()
	root.SetArgs([]string{"ca", "create", "--db", filepath.Join(t.TempDir(), "test.db")})
	if err := root.Execute(); err == nil {
		t.Fatal("Execute() without --cn expected error, got nil")
	}
}

func TestGenerateKey_RSA(t *testing.T) {
	priv, keyPEM, err := generateKey("rsa", 2048, "")
	if err != nil {
		t.Fatalf("generateKey(rsa) error = %v", err)
	}
	if _, ok := priv.(*rsa.PrivateKey); !ok {
		t.Errorf("generateKey(rsa) returned %T, want *rsa.PrivateKey", priv)
	}
	if len(keyPEM) == 0 {
		t.Error("generateKey(rsa) returned empty PEM")
	}
}

func TestGenerateKey_ECDSA(t *testing.T) {
	priv, keyPEM, err := generateKey("ecdsa", 0, "P-256")
	if err != nil {
		t.Fatalf("generateKey(ecdsa) error = %v", err)
	}
	if _, ok := priv.(*ecdsa.PrivateKey); !ok {
		t.Errorf("generateKey(ecdsa) returned %T, want *ecdsa.PrivateKey", priv)
	}
	if len(keyPEM) == 0 {
		t.Error("generateKey(ecdsa) returned empty PEM")
	}
}

// Helpers

func loadRootCAFromDB(t *testing.T, dbPath string) (store.Ca, []byte) {
	t.Helper()
	ctx := context.Background()

	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		t.Fatalf("OpenDB() error = %v", err)
	}
	defer d.Close()

	q := store.New(d.SqlDB())
	ca, err := q.GetRootCA(ctx)
	if err != nil {
		t.Fatalf("GetRootCA() error = %v", err)
	}

	key, err := q.LoadKey(ctx, ca.Serial)
	if err != nil {
		t.Fatalf("LoadKey() error = %v", err)
	}

	return ca, key
}

func parseCertPEMFromString(t *testing.T, certPEM string) *x509.Certificate {
	t.Helper()
	block, _ := pem.Decode([]byte(certPEM))
	if block == nil {
		t.Fatal("cert PEM decode failed")
	}
	cert, err := x509.ParseCertificate(block.Bytes)
	if err != nil {
		t.Fatalf("ParseCertificate error = %v", err)
	}
	return cert
}

