func TestTLS_ServerCertVerification(t *testing.T) {
	ctx := context.Background()
	tmpDir := t.TempDir()
	dbPath := filepath.Join(tmpDir, "test.db")

	run := func(args ...string) {
		t.Helper()
		cmd := cli.NewRoot()
		cmd.SetArgs(args)
		if err := cmd.Execute(); err != nil {
			t.Fatalf("gossl %v: %v", args, err)
		}
	}

	run("ca", "create", "--cn", "TLS Root CA", "--db", dbPath, "--key-size", "2048")
	run("ca", "create", "--cn", "TLS Intermediate", "--db", dbPath, "--key-size", "2048")
	run("cert", "issue", "--cn", "localhost", "--ca", "TLS Intermediate",
		"--san", "localhost,127.0.0.1", "--db", dbPath, "--key-size", "2048")

	serverCertPath := filepath.Join(tmpDir, "server.pem")
	serverKeyPath := filepath.Join(tmpDir, "server-key.pem")
	caBundlePath := filepath.Join(tmpDir, "ca-bundle.pem")

	certSerial := getCertSerial(t, dbPath, "localhost")
	run("cert", "export", "--serial", certSerial, "--db", dbPath, "--out", serverCertPath, "--chain")
	exportKey(t, dbPath, certSerial, serverKeyPath)
	exportCABundle(t, dbPath, caBundlePath)

	nginxConf := filepath.Join(tmpDir, "nginx.conf")
	writeFile(t, nginxConf, `
events {}
http {
    server {
        listen 443 ssl;
        ssl_certificate /etc/nginx/certs/server.pem;
        ssl_certificate_key /etc/nginx/certs/server-key.pem;

        location / {
            return 200 "TLS OK\n";
            add_header Content-Type text/plain;
        }
    }
}
`)

	req := testcontainers.ContainerRequest{
		Image:        "nginx:alpine",
		ExposedPorts: []string{"443/tcp"},
		WaitingFor:   wait.ForListeningPort("443/tcp").WithStartupTimeout(30 * time.Second),
		Files: []testcontainers.ContainerFile{
			{HostFilePath: serverCertPath, ContainerFilePath: "/etc/nginx/certs/server.pem"},
			{HostFilePath: serverKeyPath, ContainerFilePath: "/etc/nginx/certs/server-key.pem"},
			{HostFilePath: nginxConf, ContainerFilePath: "/etc/nginx/nginx.conf"},
		},
	}

	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
		ContainerRequest: req,
		Started:          true,
	})
	if err != nil {
		t.Fatalf("starting nginx container: %v", err)
	}
	defer container.Terminate(ctx)

	mappedPort, err := container.MappedPort(ctx, "443")
	if err != nil {
		t.Fatalf("getting mapped port: %v", err)
	}

	host, err := container.Host(ctx)
	if err != nil {
		t.Fatalf("getting host: %v", err)
	}

	addr := fmt.Sprintf("https://%s:%s", host, mappedPort.Port())

	// Connect with our CA bundle as trusted root
	rootCAs := x509.NewCertPool()
	caPEM, err := os.ReadFile(caBundlePath)
	if err != nil {
		t.Fatalf("reading CA bundle: %v", err)
	}
	rootCAs.AppendCertsFromPEM(caPEM)

	client := &http.Client{
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{
				RootCAs:    rootCAs,
				ServerName: "localhost",
			},
		},
		Timeout: 5 * time.Second,
	}

	resp, err := client.Get(addr)
	if err != nil {
		t.Fatalf("GET %s: %v", addr, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Errorf("status = %d, want 200", resp.StatusCode)
	}

	body, _ := io.ReadAll(resp.Body)
	t.Logf("Response: %s", body)
}

// --- Helpers ---

func getCertSerial(t *testing.T, dbPath, cn string) string {
	t.Helper()
	ctx := context.Background()

	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		t.Fatalf("OpenDB: %v", err)
	}
	defer d.Close()

	q := store.New(d.SQLDB())
	cert, err := q.GetCertByCN(ctx, cn)
	if err != nil {
		t.Fatalf("GetCertByCN(%s): %v", cn, err)
	}
	return cert.Serial
}

func exportKey(t *testing.T, dbPath, serial, outPath string) {
	t.Helper()
	ctx := context.Background()

	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		t.Fatalf("OpenDB: %v", err)
	}
	defer d.Close()

	q := store.New(d.SQLDB())
	keyPEM, err := q.LoadKey(ctx, serial)
	if err != nil {
		t.Fatalf("LoadKey(%s): %v", serial, err)
	}

	if err := os.WriteFile(outPath, keyPEM, 0600); err != nil {
		t.Fatalf("writing key: %v", err)
	}
}

func exportCABundle(t *testing.T, dbPath, outPath string) {
	t.Helper()
	ctx := context.Background()

	d, err := store.OpenDB(ctx, dbPath)
	if err != nil {
		t.Fatalf("OpenDB: %v", err)
	}
	defer d.Close()

	q := store.New(d.SQLDB())
	cas, err := q.ListCAs(ctx)
	if err != nil {
		t.Fatalf("ListCAs: %v", err)
	}

	var bundle string
	for _, ca := range cas {
		bundle += ca.CertPem
	}

	if err := os.WriteFile(outPath, []byte(bundle), 0644); err != nil {
		t.Fatalf("writing CA bundle: %v", err)
	}
}

func buildMTLSClient(t *testing.T, caBundlePath, certPath, keyPath string) *http.Client {
	t.Helper()

	clientCert, err := tls.LoadX509KeyPair(certPath, keyPath)
	if err != nil {
		t.Fatalf("LoadX509KeyPair: %v", err)
	}

	rootCAs := x509.NewCertPool()
	caPEM, err := os.ReadFile(caBundlePath)
	if err != nil {
		t.Fatalf("reading CA bundle: %v", err)
	}
	rootCAs.AppendCertsFromPEM(caPEM)

	return &http.Client{
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{
				Certificates: []tls.Certificate{clientCert},
				RootCAs:      rootCAs,
				ServerName:   "localhost",
			},
		},
		Timeout: 5 * time.Second,
	}
}

func writeFile(t *testing.T, path, content string) {
	t.Helper()
	if err := os.WriteFile(path, []byte(content), 0644); err != nil {
		t.Fatalf("writing %s: %v", path, err)
	}
}

