 78→func parsePrivateKey(keyPEM []byte) (any, error) {
 79→	block, _ := pem.Decode(keyPEM)
 80→	if block == nil {
 81→		return nil, fmt.Errorf("failed to decode PEM")
 82→	}
 83→	switch block.Type {
 84→	case "RSA PRIVATE KEY":
