			clientCAs = x509.NewCertPool()
		}
	}

	return startServer(tlsCert, clientCAs, addr, port, mtls, verbose)
}

func startServer(cert tls.Certificate, clientCAs *x509.CertPool, addr string, port int, mtls, verbose bool) error {
	clientAuth := tls.NoClientCert
	if mtls {
		clientAuth = tls.RequireAndVerifyClientCert
	}

	tlsConf := &tls.Config{
		MinVersion:   tls.VersionTLS13,
		Certificates: []tls.Certificate{cert},
		ClientAuth:   clientAuth,
		ClientCAs:    clientCAs,
	}

	mux := http.NewServeMux()
	mux.HandleFunc("/", echoHandler(verbose))

	server := &http.Server{
		Addr:      fmt.Sprintf(":%d", port),
		Handler:   mux,
		TLSConfig: tlsConf,
	}

	fmt.Printf("Listening on https://0.0.0.0:%d", port)
	if mtls {
		fmt.Print(" (mTLS enabled)")
	}
	fmt.Println()

	return server.ListenAndServeTLS("", "")
}

type echoResponse struct {
	URI     string            `json:"uri"`
	Method  string            `json:"method"`
	Headers map[string]string `json:"headers,omitempty"`
	Form    map[string]string `json:"form,omitempty"`
	Body    string            `json:"body,omitempty"`
	Peer    *peerInfo         `json:"peer,omitempty"`
}

type peerInfo struct {
	Subject string `json:"subject"`
	Issuer  string `json:"issuer"`
	Serial  string `json:"serial"`
	Expiry  string `json:"expiry"`
}

func echoHandler(verbose bool) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		resp := echoResponse{
			URI:    r.RequestURI,
			Method: r.Method,
		}

		if verbose {
			resp.Headers = make(map[string]string)
			for k, v := range r.Header {
				resp.Headers[k] = v[0]
			}
		}

		if r.Method == http.MethodPost || r.Method == http.MethodPut {
			_ = r.ParseForm() // best-effort; form data is optional for echo response
			if len(r.Form) > 0 {
				resp.Form = make(map[string]string)
				for k, v := range r.Form {
					resp.Form[k] = v[0]
				}
			}
		}

		if r.TLS != nil && len(r.TLS.PeerCertificates) > 0 {
			peer := r.TLS.PeerCertificates[0]
			resp.Peer = &peerInfo{
				Subject: peer.Subject.String(),
				Issuer:  peer.Issuer.String(),
				Serial:  fmt.Sprintf("%X", peer.SerialNumber),
				Expiry:  peer.NotAfter.Format(time.RFC3339),
			}
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(resp) // best-effort write to client
	}
}

